#include <bits/stdc++.h>
#define int long long
using namespace std;
int qpow (int a, int b, int p) {
	int res = 1;
	while (b) {
		if (b & 1) {
			res = res * a % p;
		}
		a = a * a % p;
		b >>= 1;
	}
	return res;
}
int EXBSGS (int a, int b, int p) {
	a %= p;
	b %= p;
	if (b == 1 || p == 1) {
		return 0;
	}
	int d, k = 0, A = 1;
	while (true) {
		d = __gcd (a, p);
		if (d == 1) {
			break;
		}
		if (b % d != 0) {
			return -1;
		}
		k++;
		b /= d;
		p /= d;
		A = A * (a / d) % p;
		if (A == b) {
			return k;
		}
	}
	int m = ceil (sqrt (p));
	int t = b;
	unordered_map <int, int> mp;
	for (int i = 0; i < m; i++) {
		mp[t] = i;
		t = t * a % p;
	}
	int mi = qpow (a, m, p);
	t = A;
	for (int i = 1; i <= m; i++) {
		t = t * mi % p;
		if (mp.count (t)) {
			return i * m - mp[t] + k;
		}
	} 
	return -1;
}
signed main() {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	int p, b, n;
	while (true) {
		cin >> b >> p >> n;
		if (p == 0 && b == 0 && n == 0) {
			return 0;
		}
		int ans = EXBSGS (b, n, p);
		if (ans == -1) {
			cout << "No Solution\n";
		} else {
			cout << ans << '\n';
		}
	}
	return 0;
}
